cat > ParseBinlog.cs << 'EOF'
using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program
{
    static void Main(string[] args)
    {
        var binlogPath = args.Length > 0 ? args[0] : "build.binlog";
        var build = BinaryLog.ReadBuild(binlogPath);

        // Collect all errors
        var errors = new List<(string Project, string Code, string File, int Line, string Message)>();

        build.VisitAllChildren<Error>(error =>
        {
            var project = GetProjectName(error);
            errors.Add((project, error.Code ?? "", error.File ?? "", error.LineNumber, error.Text ?? error.ToString()));
        });

        Console.WriteLine($"=== BUILD RESULT: {(build.Succeeded ? "SUCCESS" : "FAILED")} ===");
        Console.WriteLine($"Total errors: {errors.Count}");
        Console.WriteLine();

        // Group by project
        var byProject = errors.GroupBy(e => e.Project).OrderBy(g => g.Key);
        foreach (var group in byProject)
        {
            Console.WriteLine($"--- Project: {group.Key} ---");
            foreach (var err in group)
            {
                var location = string.IsNullOrEmpty(err.File) ? "" : $" [{Path.GetFileName(err.File)}:{err.Line}]";
                Console.WriteLine($"  {err.Code}{location}: {err.Message}");
            }
            Console.WriteLine();
        }

        // Also check for failed targets/tasks
        Console.WriteLine("=== FAILED PROJECTS (from build structure) ===");
        build.VisitAllChildren<Project>(p =>
        {
            if (!p.Succeeded)
            {
                Console.WriteLine($"  FAILED: {p.Name} ({Path.GetFileName(p.ProjectFile)})");
            }
        });
    }

    static string GetProjectName(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p)
                return Path.GetFileNameWithoutExtension(p.ProjectFile ?? p.Name);
            current = current.Parent;
        }
        return "(unknown)";
    }
}
EOF

