using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

class Program2
{
    static void Main(string[] args)
    {
        var binlogPath = "build.binlog";
        var build = BinaryLog.ReadBuild(binlogPath);

        // Check for package restore issues
        Console.WriteLine("=== WARNINGS (package/restore related) ===");
        build.VisitAllChildren<Warning>(w =>
        {
            if (w.Code != null && (w.Code.StartsWith("NU") || w.Text.Contains("package") || w.Text.Contains("restore")))
            {
                var project = GetProjectName(w);
                Console.WriteLine($"  [{project}] {w.Code}: {w.Text}");
            }
        });
        Console.WriteLine();

        // Look for NuGet restore details
        Console.WriteLine("=== PACKAGE REFERENCES in Services project ===");
        build.VisitAllChildren<Project>(p =>
        {
            if (p.ProjectFile != null && p.ProjectFile.Contains("Services"))
            {
                Console.WriteLine($"  Project: {p.ProjectFile}");
                p.VisitAllChildren<Item>(item =>
                {
                    if (item.Name == "PackageReference" || item.Name == "Reference")
                    {
                        Console.WriteLine($"    {item.Name}: {item.Text}");
                    }
                });
            }
        });
        Console.WriteLine();

        // Check which projects depend on Services
        Console.WriteLine("=== PROJECT REFERENCES / DEPENDENCIES ===");
        build.VisitAllChildren<Project>(p =>
        {
            p.VisitAllChildren<Item>(item =>
            {
                if (item.Name == "ProjectReference")
                {
                    Console.WriteLine($"  {Path.GetFileNameWithoutExtension(p.ProjectFile)} -> {item.Text}");
                }
            });
        });
    }

    static string GetProjectName(BaseNode node)
    {
        var current = node.Parent;
        while (current != null)
        {
            if (current is Project p)
                return Path.GetFileNameWithoutExtension(p.ProjectFile ?? p.Name);
            current = current.Parent;
        }
        return "(unknown)";
    }
}
EOF
