    }
});
Console.WriteLine();

Console.WriteLine("=== PROJECT REFERENCES ===");
build.VisitAllChildren<AddItem>(item =>
{
    if (item.Name == "ProjectReference")
    {
        Console.WriteLine($"  {item.Text}");
    }
});
Console.WriteLine();

Console.WriteLine("=== MESSAGES containing 'Newtonsoft' ===");
build.VisitAllChildren<Message>(m =>
{
    if ((m.Text ?? "").Contains("Newtonsoft"))
    {
        Console.WriteLine($"  {m.Text?.Substring(0, Math.Min(200, m.Text.Length))}");
    }
});
