using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");

// Get details about Item nodes
Console.WriteLine("=== PackageReference ITEMS with metadata ===");
build.VisitAllChildren<Item>(item =>
{
    if (item.Name == "PackageReference")
    {
        var parent = item.Parent;
        string parentInfo = parent?.ToString() ?? "no parent";
        // Get the item spec from NamedNode
        Console.WriteLine($"  Item: {item.Text} | Parent: {parentInfo}");
        // Print children/metadata
        if (item.HasChildren)
        {
            foreach (var child in item.Children)
            {
                Console.WriteLine($"    Metadata: {child}");
            }
        }
    }
});
Console.WriteLine();

// Check the project tree for Services
Console.WriteLine("=== Services project tree (targets/tasks) ===");
build.VisitAllChildren<Project>(p =>
{
    if (p.ProjectFile != null && p.ProjectFile.Contains("Services"))
    {
        Console.WriteLine($"Project: {p.ProjectFile}");
        // List direct children
        if (p.HasChildren)
        {
            foreach (var child in p.Children.Take(30))
            {
                Console.WriteLine($"  {child.GetType().Name}: {child.ToString()?.Substring(0, Math.Min(100, child.ToString()?.Length ?? 0))}");
            }
        }
    }
});
EOF
