using System;
using System.IO;
using System.Linq;
using System.Collections.Generic;
using Microsoft.Build.Logging.StructuredLogger;

var build = BinaryLog.ReadBuild("build.binlog");

// Get Properties for Services
Console.WriteLine("=== Services.csproj Properties (key ones) ===");
build.VisitAllChildren<Project>(p =>
{
    if (p.ProjectFile != null && p.ProjectFile.Contains("Services") && p.ProjectFile.EndsWith(".csproj"))
    {
        var propsFolder = p.Children.OfType<Folder>().FirstOrDefault(f => f.Name == "Properties");
        if (propsFolder != null)
        {
            foreach (var prop in propsFolder.Children.OfType<Property>())
            {
                if (prop.Name == "TargetFramework" || prop.Name == "PackageReference" || 
                    prop.Name == "ProjectDir" || prop.Name == "RootNamespace")
                {
                    Console.WriteLine($"  {prop.Name} = {prop.Value}");
                }
            }
        }
        // only first project evaluation
        break;
    }
});
Console.WriteLine();

// Look for the csproj content or Items added
Console.WriteLine("=== Items added in Services build ===");
build.VisitAllChildren<Project>(p =>
{
    if (p.ProjectFile != null && p.ProjectFile.Contains("Services") && p.ProjectFile.EndsWith(".csproj"))
    {
        p.VisitAllChildren<AddItem>(ai =>
        {
            if (ai.Name == "PackageReference")
            {
                Console.WriteLine($"  AddItem PackageReference:");
                foreach (var child in ai.Children)
                {
                    Console.WriteLine($"    {child}");
                }
            }
        });
        break;
    }
});
Console.WriteLine();

// Look at the full error context
Console.WriteLine("=== ERROR CONTEXT ===");
build.VisitAllChildren<Error>(e =>
{
    Console.WriteLine($"Error: {e.Code} in {e.File}:{e.LineNumber}");
    Console.WriteLine($"  Text: {e.Text}");
    Console.WriteLine($"  ProjectFile: {e.ProjectFile}");
    Console.WriteLine();
});

// Check for other projects in the solution
Console.WriteLine("=== ALL PROJECTS IN BUILD ===");
var seen = new HashSet<string>();
build.VisitAllChildren<Project>(p =>
{
    if (p.ProjectFile != null && seen.Add(p.ProjectFile))
    {
        Console.WriteLine($"  {p.ProjectFile}");
    }
});
EOF
