{
    var node = (BaseNode)csc;
    while (node.Parent != null)
    {
        node = node.Parent;
        if (node is Project p && p.ProjectFile != null && p.ProjectFile.Contains("Api"))
        {
            Console.WriteLine($"CscTask found in Api project");
            // Check for errors in Api
            p.VisitAllChildren<Error>(e => Console.WriteLine($"  Error: {e.Code}: {e.Text}"));
            break;
        }
    }
});
Console.WriteLine();

