Console.WriteLine("=== Project references from Api ===");
build.VisitAllChildren<ProjectEvaluation>(pe =>
{
    if (pe.ProjectFile != null && pe.ProjectFile.Contains("Api"))
    {
        pe.VisitAllChildren<AddItem>(ai =>
        {
            if (ai.Name == "ProjectReference" && ai.HasChildren)
            {
                foreach (var c in ai.Children)
                    Console.WriteLine($"  Api ProjectReference: {c}");
            }
        });
    }
});
Console.WriteLine();

// Check Core project
Console.WriteLine("=== Core project errors ===");
build.VisitAllChildren<Project>(p =>
{
    if (p.ProjectFile != null && p.ProjectFile.Contains("Core") && p.ProjectFile.EndsWith(".csproj"))
    {
        p.VisitAllChildren<Error>(e => Console.WriteLine($"  Error: {e.Code}: {e.Text}"));
    }
});
Console.WriteLine("(none if blank)");
Console.WriteLine();

// Check the source file lines from the error
Console.WriteLine("=== UserService.cs lines referenced in errors (2, 3, 22) ===");
Console.WriteLine("Line 2 error: using Newtonsoft.Json;");
Console.WriteLine("Line 3 error: using Newtonsoft.Json.Linq;");
Console.WriteLine("Line 22 error: JObject usage");
Console.WriteLine();

// Check target framework
