build.VisitAllChildren<ProjectEvaluation>(pe =>
{
    if (pe.ProjectFile != null)
    {
        pe.VisitAllChildren<Property>(prop =>
        {
            if (prop.Name == "TargetFramework")
                Console.WriteLine($"  {Path.GetFileName(pe.ProjectFile)}: {prop.Value}");
        });
    }
});
